'prop 1 = nazwa pola referencji np. pKlient
function std_remove_hli(byref pHLI)
	dim strRefFldName : strRefFldName = pHLI.prop(1)	

	dim strMatchField: strMatchField = ""
	if (pHLI.exists(4)) then
		strMatchField = pHLI.prop(4)
	end if

	dim pStdObjDef:set pStdObjDef = doc_.stdobjdef.getobjdef(page_.root.type)

	dim nFldNr:nFldNr = pStdObjDef.getfieldindex(strRefFldName)

	set page_.root.field(nFldNr) = nothing
	
end function

function c8711_onsuggquery(byref pEditCtrl,byval strEnteredVal,byref strWhere,byref strOrder,byref strJoin)
	'wyszukuje po dowolnym znaku, nie tylko po początku
	strWhere = "strNazwa like'%" + doc_.afc.convert.str2sql(cstr(strEnteredVal)) + "%'"
end function
